var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"엇-차!","JPN":"そりゃっ！","ENG":"Oopsie!","TWN":"喝啊！"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"해, 해치웠나?","JPN":"た、倒したんですか？","ENG":"D-did we get them?","TWN":"解、解決了嗎？"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"쉿, 그런 말 하면 큰일나요.","JPN":"しっ、そんなこと言っちゃダメですよ。","ENG":"Shh, don't say that; you're going to jinx it.","TWN":"噓，說那種話會很不妙喔。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"그보다 사람을 공격하지 않고 납치하는 침식체는 저도 처음 보네요.","JPN":"それより、人を襲わずに拉致する侵食体なんて初めて見ます。","ENG":"By the way, I've never seen C.O.s that abduct people instead of attacking them before.","TWN":"不過我還是第一次見到不攻擊人類，而是綁架人類的侵蝕體。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"침식체가 당신에게 첫눈에 반하기라도 한 걸까요?","JPN":"侵食体が一目惚れでもしたんでしょうか？","ENG":"Did they fall in love with you at first sight?","TWN":"該不會是侵蝕體對妳一見鍾情了吧？"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"아무렇지 않게 무서운 소리 하지 마세요!!","JPN":"しれっと怖いことを言わないでください！？","ENG":"How can you say something so terrible?","TWN":"不要若無其事地說這麼嚇人的話！！"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"남자 좀 찾아달랬더니 여자를 데려오질 않나, 침식체를 데려오질 않나!","JPN":"運命の相手を見つけてほしいと言ってたのに、女の人やら侵食体やらを連れてくるなんて！","ENG":"I asked for the man of my dreams, and they brought me a woman and C.O.s instead!","TWN":"我委託你們找的是男人，而不是女人或是侵蝕體！"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"당연히 해낼 수 있을 것처럼 자신 있게 말해놓고, 일 처리가 뭐 이따위야?!!","JPN":"自信満々に呼び出すとか言ってたくせに、仕事ぶりがめちゃくちゃじゃない！","ENG":"They acted as if they could find him. How could they do this to me?","TWN":"當初說得信誓旦旦的，結果呢，這算什麼？！！"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"아, 당신이 운명의 상대를 찾는다던 그 의뢰인?","JPN":"あ、君が運命の相手を探してる依頼人？","ENG":"Ah, so you're their client looking for a soul mate.","TWN":"啊，妳就是那位尋找命運之人的委託人？"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"후후, 저로선 남자든 여자든 딱히 상관없긴 한데요.","JPN":"ふふ、私的には男でも女でもどっちでもいいんですけど。","ENG":"Hah hah. I don't care if you're a man or woman.","TWN":"呵呵，我倒是不會特別在意是男還是女。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_LAUGH"}}}},{"id":"L18_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"이쪽에서 단호하게 사양하겠습니다!","JPN":"私からきっぱりとお断りします！","ENG":"I do!","TWN":"容我嚴正拒絕！"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_LAUGH"}}}},{"id":"L19_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"개인의 취향에 대해서는 존중하겠지만 어쨌든 전 남자를 찾고 있어서요.","JPN":"人の好みは尊重しますが、とにかく私は男の人を探しています。","ENG":"I respect your sexual orientation, but I'm personally looking for a man.","TWN":"我尊重妳的個人喜好，但我要男的。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_LAUGH"}}}},{"id":"L21_1","type":"dialog","speaker":"ROSARIA_FALLEN_SUMMER_NULL","text":{"KOREA":"거 참 변덕스러운 고객이로구나.","JPN":"おやおや、気まぐれな客じゃな。","ENG":"You're such a capricious customer.","TWN":"真是個善變的顧客。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_SUMMER_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ROSARIA_FALLEN_SUMMER_NULL","text":{"KOREA":"하지만 걱정 말거라. 내 권능이 실패 따윌 할 리가 없지 않느냐?","JPN":"だが、心配することはない。妾の権能が失敗するわけがないのじゃ。","ENG":"But worry not. There's no way my power fails me.","TWN":"但別擔心，我的力量怎麼可能會失敗呢？"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"무슨 소리죠? 이게 실수가 아니었다고요?","JPN":"どういうことですか？　これが失敗じゃなかったと？","ENG":"What are you talking about? Are you telling me this wasn't a mistake?","TWN":"什麼意思？這還不算失敗嗎？"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ROSARIA_FALLEN_SUMMER_NULL","text":{"KOREA":"소환된 것이 네 운명의 상대가 아니라고 해도, 결국 인과의 고리는 서로를 잡아당기기 마련이지.","JPN":"召喚されたのが其方の運命の相手じゃなかったとしても、結局因果の輪は互いを引き寄せるものじゃ。","ENG":"What I summoned may not be your soul mate, but the ones within the same ring of causality are bound to pull each other.","TWN":"即使召喚出來的不是妳命運之人，但因果之環終究會讓兩人相見的。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_SUMMER_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ROSARIA_FALLEN_SUMMER_NULL","text":{"KOREA":"이 여자와 함께 있다 보면 자연스레 네 운명의 상대와도 마주치게 될 것이다.","JPN":"この女と一緒にいる間に、自然と其方の運命の相手に出会うことになるだろう。","ENG":"Stay with her, and you'll eventually come across your soul mate.","TWN":"只要和這位小姐在一起，妳自然會遇到命運之人。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"인과의 고리? 애초에 운명이니 그런 게 정말로 있기나 합니까?","JPN":"因果の輪？　そもそも運命なんかが本当に存在するんですか？","ENG":"The ring of causality? Does destiny even exist?","TWN":"因果之環？難道命運這種東西真的存在嗎？"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ROSARIA_FALLEN_SUMMER_NULL","text":{"KOREA":"성공하지 못한다면 전액환불보장이니라.","JPN":"成功できなかったら、全額払い戻しを約束しよう。","ENG":"If you don't meet your man of dreams, I'll give you a full refund.","TWN":"如果沒有成功的話，我會全額退款。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_SUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"윽...... 그렇게까지 나오신다면야 믿어보죠.","JPN":"うっ……そこまで言うなら信じてみます。","ENG":"Gah... Okay, if you say so, I'll trust you.","TWN":"唔……既然這樣，那我就再相信妳一次。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"오~ 그럼 이제부터 제가 사랑의 큐피트가 되는 거네요?","JPN":"おぉ～じゃあ、これからは私が愛のキューピットになるんですか？","ENG":"Ooo, does this mean I'm your Cupid now?","TWN":"哦~那我現在開始就是愛神丘比特嘍？"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROSARIA_FALLEN_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_LAUGH"}}}},{"id":"L32_1","type":"dialog","speaker":"ROSARIA_FALLEN_SUMMER_NULL","text":{"KOREA":"잘 아는구나. 필멸자. 이 음침한 처녀와 이어질 상대는 어디에 있을 것 같으냐?","JPN":"よくわかっておるようじゃな。この陰気な乙女と結ばれる相手はどこにいると思う？","ENG":"You're shrewd, mortal. Where do you think this gloomy maiden's soul mate is?","TWN":"沒錯，必滅者。妳覺得這個陰沉的姑娘的另一半會在什麼地方？"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROSARIA_FALLEN_SUMMER_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_LAUGH"}}}},{"id":"L33_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"흐음...... 어디보자~","JPN":"ふむ……そうですね。","ENG":"Hmm... Let me think...","TWN":"嗯……讓我看看～"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROSARIA_FALLEN_SUMMER_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"연애라면 역시 베테랑에게 조언을 구하는 게 좋겠죠?","JPN":"恋愛のことなら、やっぱり恋愛のベテランにアドバイスをもらったほうがいいんじゃないですか？","ENG":"I suggest we consult a love expert.","TWN":"戀愛的事情，果然還是該去問專家才對！"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROSARIA_FALLEN_SUMMER_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"저기 저쪽 호텔 리조트에 엄청 예쁜 언니가 있는 것 같아요!","JPN":"あそこのホテルリゾートにとても綺麗なお姉さんがいるみたいですし！","ENG":"It seems there's an extremely beautiful lady at the hotel resort over there.","TWN":"那邊的度假飯店好像有一個非常漂亮的姐姐！"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROSARIA_FALLEN_SUMMER_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L36_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"주변에 사람들이 엄청 몰려있는 걸 보면 분명 인기 많은 사람이겠죠?","JPN":"お姉さんの周りに人がたくさん集まってるところを見る限り、きっと人気者なんでしょう？","ENG":"Seeing how she's surrounded by a crowd of people, she's got to be popular, right?","TWN":"她周圍聚集了很多人，應該很受歡迎吧？"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROSARIA_FALLEN_SUMMER_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"저 언니에게 물어보면 분명 운명의 상대를 찾는 방법을 알려줄 지도 몰라요!","JPN":"そのお姉さんに聞いてみれば、きっと運命の相手を探す方法を教えてくれると思いますよ！","ENG":"Maybe she can tell you how to find your soul mate.","TWN":"我們去問問那個姐姐，她說不定會告訴我們如何找到命運之人！"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROSARIA_FALLEN_SUMMER_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_LAUGH"}}}},{"id":"L39_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"그런 사람이 어디에 있죠? 눈이 엄청 좋으신 것 같네요. 전 안 보이는데......","JPN":"そんな人いました？　目がとてもいいですね。私には見えませんが……","ENG":"Where is she? You must have super vision or something. I can't see her.","TWN":"妳說的那個人在哪裡？妳的眼力真好，我什麼也沒看見……"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"ROSARIA_FALLEN_SUMMER_NULL","text":{"KOREA":"좋다! 가보자꾸나 필멸자! 돌발 이벤트란 언제나 흥미진진한 법이지!","JPN":"よし！　行くとしよう！　突発イベントとはいつも興味深いものじゃ！","ENG":"Alright, let's go, mortal! Sudden events like this are always exciting!","TWN":"好！走吧，必滅者！突發事件總是讓人熱血沸騰啊！"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};